input.oldString:
.wordmark::before {
  content: "";
  display: inline-block;
  width: 24px;
  height: 24px;
  background: var(--fg);
  border-radius: 4px;
  margin-right: 6px;
  flex-shrink: 0;
}

input.newString:
.wordmark img {
  height: 24px;
  width: auto;
  display: block;
  margin-right: 6px;
  flex-shrink: 0;
}

input.oldString:
.hero-photo .photo-placeholder {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  color: var(--muted);
  opacity: 0.6;
  position: relative;
  z-index: 1;
  text-align: center;
  font-size: 13px;
  font-weight: 500;
  padding: 12px;
}

.hero-photo .photo-placeholder .icon {
  font-size: 32px;
  opacity: 0.5;
  line-height: 1;
}

input.newString:
.hero-photo .photo-logo {
  position: relative;
  z-index: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
  padding: 20%;
}

.hero-photo .photo-logo img {
  width: 100%;
  height: 100%;
  object-fit: contain;
  opacity: 0.85;
}

input.oldString:
.hero-photo .leaf-decor {
  position: absolute;
  width: 120px;
  height: 120px;
  border-radius: 0 80% 0 80%;
  background: linear-gradient(135deg, rgba(12, 100, 44, 0.06) 0%, rgba(89, 157, 156, 0.10) 100%);
  top: 15%;
  right: -20px;
  transform: rotate(15deg);
}

.hero-photo .leaf-decor-2 {
  position: absolute;
  width: 80px;
  height: 80px;
  border-radius: 80% 0 80% 0;
  background: linear-gradient(225deg, rgba(160, 168, 140, 0.10) 0%, rgba(89, 157, 156, 0.06) 100%);
  bottom: 10%;
  left: -10px;
  transform: rotate(-10deg);
}

input.newString:
.hero-photo .leaf-decor {
  position: absolute;
  width: 100px;
  height: 100px;
  border-radius: 0 80% 0 80%;
  background: linear-gradient(135deg, rgba(12, 100, 44, 0.05) 0%, rgba(89, 157, 156, 0.08) 100%);
  top: 10%;
  right: -15px;
  transform: rotate(15deg);
}

.hero-photo .leaf-decor-2 {
  position: absolute;
  width: 60px;
  height: 60px;
  border-radius: 80% 0 80% 0;
  background: linear-gradient(225deg, rgba(160, 168, 140, 0.08) 0%, rgba(89, 157, 156, 0.04) 100%);
  bottom: 8%;
  left: -10px;
  transform: rotate(-10deg);
}
